import{_ as o,o as r,c as n,a2 as a}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"坤宁宫","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/kunning-gong.md","filePath":"landmarks/forbidden-city/kunning-gong.md","lastUpdated":1784720050000}'),e={name:"landmarks/forbidden-city/kunning-gong.md"};function l(s,t,i,g,d,u){return r(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="坤宁宫" tabindex="-1">坤宁宫 <a class="header-anchor" href="#坤宁宫" aria-label="Permalink to &quot;坤宁宫&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1551101509-f6f2cbae3604?w=1200&amp;q=80" alt="坤宁宫"></p><blockquote><p>明代皇后的正宫，清代祭神的萨满圣殿，大婚洞房的龙凤红烛——一座坤宁宫，三层身份的交叠。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>坤宁宫是内廷后三宫的最后一座，位于交泰殿之北，与乾清宫相对，&quot;坤&quot;为地、&quot;宁&quot;为安，取《道德经》&quot;地得一以宁&quot;之意，是明代<strong>皇后的正宫</strong>。然而，今天游客看到的坤宁宫，早已不是明代皇后起居的模样——清顺治十二年（1655年），清廷仿沈阳清宁宫的规制对坤宁宫进行了彻底改造，使其成为紫禁城内<strong>萨满教祭祀的固定场所</strong>，每日宰猪祭神，烟火不绝。</p><p>更为人津津乐道的是它的第三重身份：坤宁宫<strong>东暖阁</strong>是清代皇帝大婚的<strong>洞房</strong>。康熙、同治、光绪三位皇帝的大婚均在此度过新婚之夜，龙凤花烛、百子帐幔，是紫禁城中最具人间烟火气的角落。</p><p>坤宁宫面阔九间，重檐庑殿顶，体量与乾清宫相仿，是内廷最大的宫殿之一。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面阔</strong></td><td style="text-align:left;">九间（明代原制，清代改造后内部重新分隔）</td></tr><tr><td style="text-align:left;"><strong>进深</strong></td><td style="text-align:left;">五间</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">重檐庑殿顶</td></tr><tr><td style="text-align:left;"><strong>正门</strong></td><td style="text-align:left;">偏于东侧（满族&quot;口袋房&quot;习俗，门不开在正中）</td></tr><tr><td style="text-align:left;"><strong>西四间</strong></td><td style="text-align:left;">萨满祭祀场所，设煮肉大锅、神杆、神位</td></tr><tr><td style="text-align:left;"><strong>东暖阁</strong></td><td style="text-align:left;">皇帝大婚洞房，龙凤喜床、百子帐幔</td></tr><tr><td style="text-align:left;"><strong>殿后</strong></td><td style="text-align:left;">坤宁门，通往御花园</td></tr></tbody></table><p>坤宁宫最显著的外观特征是<strong>正门偏于东侧</strong>而非居中——这是满族传统&quot;口袋房&quot;的布局习俗，是清代改造留下的最直观的民族印记。殿内空间被重新分隔：</p><ul><li><strong>西侧四间</strong>：辟为萨满祭神之所。室内靠窗设连排大锅，每日宰杀两口活猪，在神位前煮&quot;祭神肉&quot;（白水煮猪肉，不加盐酱）。祭祀时，萨满（满洲巫祝）摇铃击鼓、诵唱神歌，皇帝或亲自主祭、或遣官代祭。殿外竖立一根<strong>索伦杆</strong>（神杆），杆顶置斗盛碎肉喂乌鸦，是满族&quot;神鹊救祖&quot;传说的礼仪遗存。</li><li><strong>东暖阁</strong>：大婚洞房。室内墙壁髹红漆、绘龙凤，设龙凤喜床，床上铺百子被，帐挂百子图。新婚帝后在此共居数日，然后皇帝返回养心殿，皇后移居东西六宫。</li></ul><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="大婚洞房-帝王的-三天新婚" tabindex="-1">大婚洞房：帝王的&quot;三天新婚&quot; <a class="header-anchor" href="#大婚洞房-帝王的-三天新婚" aria-label="Permalink to &quot;大婚洞房：帝王的&quot;三天新婚&quot;&quot;">​</a></h3><p>清代皇帝大婚是举国盛典，而洞房就设在坤宁宫东暖阁。新婚之夜，帝后行&quot;合卺礼&quot;（交杯酒），共食&quot;子孙饽饽&quot;（半生饺子，取&quot;生子&quot;谐音），在龙凤花烛下度过新婚之夜。按清制，帝后在坤宁宫同住不过三日，之后皇帝即返回养心殿，皇后移居自己的寝宫——这桩婚姻从一开始就是国家典礼而非私人生活。清代在坤宁宫大婚的皇帝仅三位：<strong>康熙</strong>（11岁大婚）、<strong>同治</strong>（17岁）、<strong>光绪</strong>（18岁）。溥仪大婚时清朝已亡，但仍在坤宁宫东暖阁举行了仪式。今天游客透过东暖阁的窗棂，仍能看到那铺着百子被的龙凤喜床——红烛已熄，龙凤犹在。</p><h3 id="每日两口猪-紫禁城里的萨满祭祀" tabindex="-1">每日两口猪：紫禁城里的萨满祭祀 <a class="header-anchor" href="#每日两口猪-紫禁城里的萨满祭祀" aria-label="Permalink to &quot;每日两口猪：紫禁城里的萨满祭祀&quot;">​</a></h3><p>清代坤宁宫最令人意外的功能是它的&quot;日常&quot;：每天清晨和傍晚，这里都要举行萨满祭祀，<strong>每日宰杀两口活猪</strong>，在殿内大锅中白水煮祭。祭神肉不加任何调料，祭祀后由王公大臣分食——被皇帝&quot;赏肉&quot;是极大的荣耀，但那白水煮猪肉的滋味可想而知，不少大臣以各种借口推辞&quot;赏肉&quot;。这套祭祀从清初一直延续到清末，近三百年间坤宁宫的锅里几乎日日肉香不绝，殿外的神杆上天天有乌鸦啄食碎肉。一座皇后寝宫变成了萨满圣殿，是满族入关后&quot;国语骑射&quot;祖制在紫禁城最顽固的坚守。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>东暖阁洞房</strong>：透过殿东侧的窗棂窥看龙凤喜床与百子帐幔，是紫禁城最&quot;有人间温度&quot;的景观。</li><li><strong>偏置的正门</strong>：注意坤宁宫大门不在正中而偏东——这是满族口袋房习俗在紫禁城的直接体现。</li><li><strong>殿外索伦杆</strong>：殿前竖立的神杆（索伦杆）是满族萨满祭祀的标志物，杆顶饲鸦的习俗源自&quot;神鹊救祖&quot;传说。</li><li><strong>西四间祭神格局</strong>：殿内西侧的连排大锅、神位陈设，是清代萨满祭祀原貌的珍贵留存。</li><li><strong>坤宁门</strong>：殿后坤宁门是通往御花园的门户，门额&quot;坤宁门&quot;三字值得留意。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>东暖阁在东侧</strong>：洞房陈设在坤宁宫东端，从殿外东侧窗口可见，别只在殿前正面停留。</li><li><strong>与乾清宫对照</strong>：乾清（天）与坤宁（地）一前一后、一乾一坤，是故宫&quot;天地对应&quot;设计的核心一对。明代帝居乾清、后居坤宁；清代乾清转为礼仪殿、坤宁转为祭神殿——两宫的功能变迁折射了满汉文化的交融与角力。</li><li><strong>别急着去御花园</strong>：坤宁宫是后三宫的终点、御花园的起点，在这里稍作停留，感受从&quot;朝政空间&quot;到&quot;皇家园林&quot;的过渡。</li><li><strong>了解满族习俗</strong>：口袋房门、索伦杆、白水煮肉——坤宁宫的种种&quot;不合汉制&quot;之处，正是理解清代&quot;满汉双轨&quot;统治的实物教材。</li></ul><hr><p><strong>📍 位置</strong>：内廷中轴线最北端，后三宫之末 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/jiaotai-dian.html">交泰殿</a><strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/yuhua-garden.html">御花园</a>（经坤宁门向北） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',22)])])}const f=o(e,[["render",l]]);export{h as __pageData,f as default};
